// Do not edit this file as it will be overwritten if HAMR codegen is rerun

//! System assertion spec functions -- one per Petri-net place assertion in
//! the system schedule -- plus the system-level GUMBO functions they call.

#![allow(non_snake_case)]

use data::*;
use vstd::prelude::*;

use crate::system_state::SystemState;

verus! {

// ---- system-level GUMBO functions ----

pub open spec fn sysProp_NormalModeHeatOnn(
  regulator_mode: Isolette_Data_Model::Regulator_Mode,
  current_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  lower_desired_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  upper_desired_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  internal_failure: Isolette_Data_Model::Failure_Flag_i,
  heat_control: Isolette_Data_Model::On_Off) -> bool
{
  (((((lower_desired_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid) &&
    (upper_desired_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid)) &&
    (current_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid)) &&
    (regulator_mode == Isolette_Data_Model::Regulator_Mode::Normal_Regulator_Mode)) &&
    (current_tempWstatus.degrees < lower_desired_tempWstatus.degrees)) ==>
    (heat_control == Isolette_Data_Model::On_Off::Onn)
}

pub open spec fn sysProp_REQ_MRI_7(
  lower_desired_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  upper_desired_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  interface_failure: Isolette_Data_Model::Failure_Flag_i) -> bool
{
  interface_failure.flag == !((upper_desired_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid) &&
    (lower_desired_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid))
}

pub open spec fn sysProp_REQ_MRI_8(
  lower_desired_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  upper_desired_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  lower_desired_temp: Isolette_Data_Model::Temp_i,
  upper_desired_temp: Isolette_Data_Model::Temp_i,
  interface_failure: Isolette_Data_Model::Failure_Flag_i) -> bool
{
  !(interface_failure.flag) ==>
    ((lower_desired_temp.degrees == lower_desired_tempWstatus.degrees) &&
      (upper_desired_temp.degrees == upper_desired_tempWstatus.degrees))
}

pub open spec fn sysProp_lower_is_not_higher_than_upper(
  lower_desired_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  upper_desired_tempWstatus: Isolette_Data_Model::TempWstatus_i) -> bool
{
  lower_desired_tempWstatus.degrees <= upper_desired_tempWstatus.degrees
}

pub open spec fn sysProp_lower_is_lower_temp(
  lower_desired_temp: Isolette_Data_Model::Temp_i,
  upper_desired_temp: Isolette_Data_Model::Temp_i) -> bool
{
  lower_desired_temp.degrees <= upper_desired_temp.degrees
}

pub open spec fn sysProp_NormalModeAlarmOn(
  lower_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  upper_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  current_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  monitor_mode: Isolette_Data_Model::Monitor_Mode,
  interface_failure: Isolette_Data_Model::Failure_Flag_i,
  alarm_control: Isolette_Data_Model::On_Off) -> bool
{
  (((((lower_alarm_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid) &&
    (upper_alarm_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid)) &&
    (current_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid)) &&
    (monitor_mode == Isolette_Data_Model::Monitor_Mode::Normal_Monitor_Mode)) &&
    ((current_tempWstatus.degrees < lower_alarm_tempWstatus.degrees) ||
      (current_tempWstatus.degrees > upper_alarm_tempWstatus.degrees))) ==>
    (alarm_control == Isolette_Data_Model::On_Off::Onn)
}

pub open spec fn sysProp_REQ_MMI_5(
  lower_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  upper_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  interface_failure: Isolette_Data_Model::Failure_Flag_i) -> bool
{
  ((upper_alarm_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid) &&
    (lower_alarm_tempWstatus.status == Isolette_Data_Model::ValueStatus::Valid)) ==>
    !(interface_failure.flag)
}

pub open spec fn sysProp_REQ_MMI_6(
  lower_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  upper_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  lower_alarm_temp: Isolette_Data_Model::Temp_i,
  upper_alarm_temp: Isolette_Data_Model::Temp_i,
  interface_failure: Isolette_Data_Model::Failure_Flag_i) -> bool
{
  !(interface_failure.flag) ==>
    ((lower_alarm_temp.degrees == lower_alarm_tempWstatus.degrees) &&
      (upper_alarm_temp.degrees == upper_alarm_tempWstatus.degrees))
}

pub open spec fn sysProp_I_Assm_lower_alarm_tempWstatus(lower_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i) -> bool
{
  GUMBO_Library::Allowed_LowerAlarmTempWStatus_spec(lower_alarm_tempWstatus)
}

pub open spec fn sysProp_I_Assm_upper_alarm_tempWstatus(upper_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i) -> bool
{
  GUMBO_Library::Allowed_UpperAlarmTempWStatus_spec(upper_alarm_tempWstatus)
}

pub open spec fn sysProp_Allowed_AlarmTempWstatus_Ranges(
  lower_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  upper_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i) -> bool
{
  GUMBO_Library::Allowed_AlarmTempWStatus_Ranges_spec(lower_alarm_tempWstatus, upper_alarm_tempWstatus)
}

pub open spec fn sysProp_Table_A_12_LowerAlarmTemp(lower_alarm_temp: Isolette_Data_Model::Temp_i) -> bool
{
  GUMBO_Library::Allowed_LowerAlarmTemp_spec(lower_alarm_temp.degrees)
}

pub open spec fn sysProp_Table_A_12_UpperAlarmTemp(upper_alarm_temp: Isolette_Data_Model::Temp_i) -> bool
{
  GUMBO_Library::Allowed_UpperAlarmTemp_spec(upper_alarm_temp.degrees)
}

pub open spec fn sysProp_Figure_A_7(
  lower_alarm_temp: Isolette_Data_Model::Temp_i,
  upper_alarm_temp: Isolette_Data_Model::Temp_i) -> bool
{
  lower_alarm_temp.degrees <= upper_alarm_temp.degrees
}

pub open spec fn sysProp_NormalModeImpliesNoInterfaceFailure(
  monitor_mode: Isolette_Data_Model::Monitor_Mode,
  interface_failure: Isolette_Data_Model::Failure_Flag_i) -> bool
{
  (monitor_mode == Isolette_Data_Model::Monitor_Mode::Normal_Monitor_Mode) ==>
    !(interface_failure.flag)
}

pub open spec fn sysProp_Allowed_LowerAlarmTempWstatus(lower_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i) -> bool
{
  GUMBO_Library::Allowed_LowerAlarmTempWStatus_spec(lower_alarm_tempWstatus)
}

pub open spec fn sysProp_Allowed_UpperAlarmTempWstatus(upper_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i) -> bool
{
  GUMBO_Library::Allowed_UpperAlarmTempWStatus_spec(upper_alarm_tempWstatus)
}

pub open spec fn sysProp_Allowed_AlarmTempWStatus_Ranges(
  lower_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i,
  upper_alarm_tempWstatus: Isolette_Data_Model::TempWstatus_i) -> bool
{
  GUMBO_Library::Allowed_AlarmTempWStatus_Ranges_spec(lower_alarm_tempWstatus, upper_alarm_tempWstatus)
}

// ---- place assertions ----

/** assertion END_OI_Assert at place END_OI_Assert */
pub open spec fn sys_assert_END_OI_Assert(st: SystemState) -> bool
{
  (((((st.ma_lastCmd == st.ma_lastCmd) &&
    (st.mmi_lastCmd == st.mmi_lastCmd)) &&
    sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus)) &&
    sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)) &&
    sysProp_lower_is_not_higher_than_upper(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus)
}

/** assertion Post_TS_OI_Assert at place Post_TS_OI_Assert */
pub open spec fn sys_assert_Post_TS_OI_Assert(st: SystemState) -> bool
{
  ((sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)) &&
    sysProp_lower_is_not_higher_than_upper(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus)
}

/** assertion START_Regulator_Assert at place START_Regulator_Assert */
pub open spec fn sys_assert_START_Regulator_Assert(st: SystemState) -> bool
{
  sysProp_lower_is_not_higher_than_upper(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus)
}

/** assertion Post_DRF_Assert at place Post_DRF_Assert */
pub open spec fn sys_assert_Post_DRF_Assert(st: SystemState) -> bool
{
  sysProp_lower_is_not_higher_than_upper(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus)
}

/** assertion Post_MRI_Assert at place Post_MRI_Assert */
pub open spec fn sys_assert_Post_MRI_Assert(st: SystemState) -> bool
{
  (sysProp_REQ_MRI_7(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus, st.reg_interface_failure) && sysProp_REQ_MRI_8(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus, st.lower_desired_temp, st.upper_desired_temp, st.reg_interface_failure)) &&
    sysProp_lower_is_lower_temp(st.lower_desired_temp, st.upper_desired_temp)
}

/** assertion Post_MRM_Assert at place Post_MRM_Assert */
pub open spec fn sys_assert_Post_MRM_Assert(st: SystemState) -> bool
{
  (sysProp_REQ_MRI_7(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus, st.reg_interface_failure) && sysProp_REQ_MRI_8(st.lower_desired_tempWstatus, st.upper_desired_tempWstatus, st.lower_desired_temp, st.upper_desired_temp, st.reg_interface_failure)) &&
    sysProp_lower_is_lower_temp(st.lower_desired_temp, st.upper_desired_temp)
}

/** assertion END_Regulator_Assert at place END_Regulator_Assert */
pub open spec fn sys_assert_END_Regulator_Assert(st: SystemState) -> bool
{
  sysProp_NormalModeHeatOnn(st.regulator_mode, st.current_tempWstatus, st.lower_desired_tempWstatus, st.upper_desired_tempWstatus, st.internal_failure, st.heat_control)
}

/** assertion START_Monitor_Assert at place START_Monitor_Assert */
pub open spec fn sys_assert_START_Monitor_Assert(st: SystemState) -> bool
{
  (sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** assertion Post_DMF_Assert at place Post_DMF_Assert */
pub open spec fn sys_assert_Post_DMF_Assert(st: SystemState) -> bool
{
  (sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** assertion Post_MMI_Assert at place Post_MMI_Assert */
pub open spec fn sys_assert_Post_MMI_Assert(st: SystemState) -> bool
{
  (sysProp_REQ_MMI_5(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.mon_interface_failure) && sysProp_REQ_MMI_6(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.lower_alarm_temp, st.upper_alarm_temp, st.mon_interface_failure)) &&
    (!(st.mon_interface_failure.flag) ==>
      ((sysProp_Figure_A_7(st.lower_alarm_temp, st.upper_alarm_temp) && sysProp_Table_A_12_LowerAlarmTemp(st.lower_alarm_temp)) &&
        sysProp_Table_A_12_UpperAlarmTemp(st.upper_alarm_temp)))
}

/** assertion Post_MMM_Assert at place Post_MMM_Assert */
pub open spec fn sys_assert_Post_MMM_Assert(st: SystemState) -> bool
{
  ((sysProp_REQ_MMI_5(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.mon_interface_failure) && sysProp_REQ_MMI_6(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.lower_alarm_temp, st.upper_alarm_temp, st.mon_interface_failure)) &&
    (!(st.mon_interface_failure.flag) ==>
      ((sysProp_Figure_A_7(st.lower_alarm_temp, st.upper_alarm_temp) && sysProp_Table_A_12_LowerAlarmTemp(st.lower_alarm_temp)) &&
        sysProp_Table_A_12_UpperAlarmTemp(st.upper_alarm_temp)))) &&
    sysProp_NormalModeImpliesNoInterfaceFailure(st.monitor_mode, st.mon_interface_failure)
}

/** assertion END_Monitor_Assert at place END_Monitor_Assert */
pub open spec fn sys_assert_END_Monitor_Assert(st: SystemState) -> bool
{
  sysProp_NormalModeAlarmOn(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.current_tempWstatus, st.monitor_mode, st.mon_interface_failure, st.alarm_control)
}

} // verus!
